mapper.select:
SELECT 
FROM ai_capability_oauth_redirect_uri
WHERE tenant_id = #{tenantId}
  AND client_id = #{clientId}
  AND redirect_uri_hash = #{redirectUriHash}
  AND redirect_uri = #{redirectUri}
  AND status = 'ENABLED'
  AND del_flag = 0
LIMIT 1

mapper.update:
UPDATE ai_capability_oauth_redirect_uri
SET del_flag = 1, status = 'DISABLED', update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND client_id = #{clientId}
  AND del_flag = 0
